const rows = $input.all();
const results = [];
for (const row of rows) {
  const status = (row.json['Status'] || '').trim();
  const descLink = (row.json['Description Doc Link'] || '').trim();
  const title = (row.json['Episode Title'] || '').trim();
  if (status === 'Filmed' && descLink === '' && title !== '') {
    results.push(row);
  }
}
return results;

const title = $json['Episode Title'] || 'NO_TITLE';
const series = $json['Series'] || 'NO_SERIES';
const pillar = $json['Pillar'] || 'NO_PILLAR';
const towns = $json['Towns Featured'] || 'NO_TOWNS';
const points = $json['Talking Points'] || 'NO_POINTS';

const body = {
  model: "claude-haiku-4-5-20251001",
  max_tokens: 1000,
  messages: [{
    role: "user",
    content: "You are a YouTube SEO specialist for a real estate agent in the East Dallas corridor. Write a YouTube description. COMPLIANCE: Never mention sold prices or MLS data. FORMAT: Hook in first 2 lines under 150 chars, 3-4 sentence summary with keywords, TIMESTAMPS section, About Loretta paragraph, CTA: Search homes at lorettasercy.com, 10-15 hashtags. Episode: Title: " + title + " Series: " + series + " Pillar: " + pillar + " Towns: " + towns + " Talking Points: " + points
  }]
};
return { json: { ...($json), apiBody: JSON.stringify(body), debugTitle: title, debugSeries: series } };

const descItems = $input.all();
const episodeItems = $('Filter Filmed + No Description').all();
const today = new Date().toLocaleDateString('en-US', {month:'long', day:'numeric', year:'numeric'});
const results = [];
for (let i = 0; i < descItems.length; i++) {
  const episode = episodeItems[i] ? episodeItems[i].json : {};
  const descText = descItems[i].json.content[0].text;
  const docTitle = (episode['Episode Title'] || 'Untitled') + ' — YouTube Description';
  results.push({ json: { episodeTitle: episode['Episode Title'] || '', episodeNumber: episode['Episode #'] || '', series: episode['Series'] || '', docTitle: docTitle, docContent: descText, generatedDate: today } });
}
return results;

